    'Khánh Hòa': { chef_lieu: 'Nha Trang', population: '1,3 million', description: "Province côtière aux eaux turquoise, héritière du royaume Champa et capitale de la plongée en Asie du Sud-Est.", villes: ['Nha Trang', 'Cam Ranh', 'Ninh Hòa'], sites: ['Tours Cham de Po Nagar (VIIe s.)', 'Île de Vinpearl', 'Baie de Cam Ranh (ancienne base militaire US)', 'Institut océanographique de Nha Trang (1923)'], gastronomie: ['Bún cá (soupe poisson locale)', 'Nem nướng Ninh Hòa (brochettes de porc grillé)', 'Gỏi cá mai (salade de poisson cru)', 'Yến sào (nids d\'hirondelles — produit de luxe)'], histoire: "Nha Trang — territoire du royaume Champa jusqu'au XVe s. (tours de Po Nagar). Base navale française puis américaine de Cam Ranh (1965-1975). Aujourd'hui première destination touristique balnéaire du Viêt Nam.", personnages: ['Alexandre Yersin (fondateur Institut Pasteur Nha Trang, isolateur de la peste bubonique 1894)'] },
    'Lâm Đồng': { chef_lieu: 'Đà Lạt', population: '1,3 million', description: "Hauts plateaux à 1 500 m, ville des fleurs, des fraises et de l'architecture coloniale française.", villes: ['Đà Lạt', 'Bảo Lộc', 'Di Linh'], sites: ['Gare de Đà Lạt (1938, architecture coloniale)', 'Lac Xuân Hương', 'Vallée de l\'Amour', 'Forêt de pins de Đà Lạt', 'Catacombes de Linh Phước'], gastronomie: ['Fraises de Đà Lạt (uniques au Viêt Nam)', 'Artichaut de Đà Lạt (thé et soupe)', 'Bánh tráng nướng (pizza vietnamienne)', 'Rượu vang Đà Lạt (vin local)', 'Café arabica de Bảo Lộc'], histoire: "Đà Lạt fondée par Alexandre Yersin (1893) à 1 500 m sur le plateau Langbian. Station climatique française dès 1907. Résidence d'été de l'empereur Bảo Đại. Préservée des bombardements — ville la plus intacte architecturalement du Viêt Nam.", personnages: ['Alexandre Yersin (fondateur 1893)', 'Bảo Đại (résidence d\'été)', 'K\'Ho (peuple autochtone des hauts plateaux)'] },
    'An Giang': { chef_lieu: 'Long Xuyên', population: '1,9 million', description: "Province du delta du Mékong frontalière du Cambodge, peuplée de Khmers et de la communauté Hòa Hảo.", villes: ['Long Xuyên', 'Châu Đốc', 'Tân Châu'], sites: ['Montagne Sam (Núi Sam — temples)', 'Châu Đốc (pèlerinage Bà Chúa Xứ)', 'Làng bè (villages flottants sur le Mékong)', 'Forêt de Trà Sư (ibis et oiseaux)'], gastronomie: ['Bún cá (soupe poisson)', 'Mắm thái (poisson fermenté)', 'Cá lóc nướng trui (poisson grillé dans la boue)', 'Bánh bò thốt nốt (gâteau palmier)'], histoire: "Territoire khmer jusqu'au XVIIIe s. Massacre de Chan Tho (1979, frontière cambodgienne). Mouvement religieux Hòa Hảo (1939) : résistance anti-française puis anti-communiste. Province à plus forte mortalité lors des inondations du Mékong.", personnages: ['Huỳnh Phú Sổ (fondateur secte Hòa Hảo 1939)'] },
    'Kiên Giang': { chef_lieu: 'Rạch Giá', population: '1,7 million', description: "Province maritime du golfe de Thaïlande, héberge l'île de Phú Quốc — perle du Viêt Nam.", villes: ['Rạch Giá', 'Hà Tiên', 'Phú Quốc'], sites: ['Île de Phú Quốc (UNESCO, 2010)', 'Hà Tiên (temples et grottes frontaliers)', 'Parc national de Phú Quốc', 'Prison de Côn Đảo (dépendance administr.)'], gastronomie: ['Nước mắm Phú Quốc (sauce poisson — IGP, la meilleure au monde)', 'Ghẹ Phú Quốc (crabe bleu)', 'Hồ tiêu Phú Quốc (poivre — IGP)', 'Bánh canh (soupe de pâtes épaisses)'], histoire: "Phú Quốc — prison française (1949), puis prison de la République du Viêt Nam (40 000 détenus du Viêt Cong). Aujourd'hui zone économique spéciale et île touristique (Casino, Club Med). Sauce poisson nước mắm exportée dans le monde entier.", personnages: [] },
    'Đắk Lắk': { chef_lieu: 'Buôn Ma Thuột', population: '1,9 million', description: "Capitale mondiale du café robusta, hauts plateaux des peuples E Đê et M'Nông.", villes: ['Buôn Ma Thuột', 'Buôn Hồ'], sites: ['Lac Lak (éléphants)', 'Parc national Yok Don (dernier éléphants sauvages)', 'Village E Đê de Ako Dhong', 'Chutes de Dray Nur'], gastronomie: ['Café robusta de Đắk Lắk (40% du café vietnamien)', 'Thịt nướng E Đê (viande grillée style E Đê)', 'Canh chua (soupe acide)', 'Cơm lam (riz cuit dans le bambou)'], histoire: "Hauts Plateaux — territoire des peuples Degar (Montagnards). Occupés par la France (1899). Massacres des FULRO (Front de libération des Hauts Plateaux, 1958-1992). Premier objectif de l'offensive finale nord-vietnamienne (mars 1975 — offensive de Buôn Ma Thuột).", personnages: ['N\'Trang Lơng (résistant Mnong contre la France, 1912-1935)'] },
    'Đồng Nai': { chef_lieu: 'Biên Hòa', population: '3,2 millions', description: "Province industrielle jouxtant Hô Chi Minh-Ville, zone de défoliation à l'Agent Orange.", villes: ['Biên Hòa', 'Long Khánh', 'Trảng Bom'], sites: ['Parc national Cat Tien (tigres, ours)', 'Buu Long (parc rocheux)', 'Base aérienne de Biên Hòa (Agent Orange — zone la plus contaminée)'], gastronomie: ['Bưởi Tân Triều (pomelos)', 'Heo quay (cochon rôti)', 'Cá thát lát (poisson couperet farci)'], histoire: "Biên Hòa — la plus ancienne ville vietnamienne du sud (1698). Base aérienne US : opérations Ranch Hand (défoliation Agent Orange 1962-1971). Contamination aux dioxines persistante. Aujourd'hui première zone industrielle du Viêt Nam.", personnages: [] },
    'Bình Dương': { chef_lieu: 'Thủ Dầu Một', population: '2,6 millions', description: "Province la plus industrialisée du Viêt Nam, premier attrait d'investissements étrangers (Samsung, Intel).", villes: ['Thủ Dầu Một', 'Dĩ An', 'Thuận An'], sites: ['Musée de la province', 'Laque traditionnelle de Bình Dương', 'Zones industrielles de VSIP I et II'], gastronomie: ['Tương Bình Dương (sauce traditionnelle)', 'Bánh bèo (gâteaux de riz vapeur)', 'Gỏi cuốn (rouleaux frais)'], histoire: "Thủ Dầu Một, centre de la laque (sơn mài) depuis le XVIIe s. Province la plus urbanisée du Viêt Nam (>85%). Siège de nombreuses usines multinationales (Samsung, Intel, LEGO).", personnages: [] },
    'Thanh Hóa': { chef_lieu: 'Thanh Hóa', population: '3,7 millions', description: "Province la plus peuplée du centre-nord, berceau des dynasties Lê et Nguyễn.", villes: ['Thanh Hóa', 'Sầm Sơn', 'Bỉm Sơn'], sites: ['Citadelle de la Dynastie Hô (UNESCO, 1397)', 'Plage de Sầm Sơn', 'Cité Ho (première citadelle en pierre)', 'Lam Kinh (mausolée Lê Lợi)'], gastronomie: ['Nem chua Thanh Hóa (nem fermenté)', 'Bánh cuốn Phủ Lý', 'Chả tôm (crevettes grillées sur canne)', 'Nem chua rán (nem frit)'], histoire: "Thanh Hóa berceau des Lê (Lê Lợi, fondateur 1428) et des Nguyễn (Nguyễn Kim, ancêtre des seigneurs). Citadelle Hô (1397) — seule citadelle en pierre du Viêt Nam médiéval (UNESCO 2011). Pont Hàm Rồng (Dragon Jaw) — objectif aérien US n°1 (1965-1972, 871 attaques).", personnages: ['Lê Lợi (né à Thanh Hóa, libérateur 1428)', 'Hô Quý Ly (bâtisseur de la citadelle, 1397)'] },
