    'Northern Territory': { chef_lieu: 'Darwin', population: '250 000', description: "Outback australien, Uluru sacré, crocodiles et culture Aborigène vivante.", villes: ['Darwin', 'Alice Springs', 'Katherine', 'Tennant Creek'], sites: ['Uluru - Kata Tjuta (UNESCO)', 'Kakadu (UNESCO, art rupestre 20 000 ans)', 'Litchfield (piscines naturelles)', 'Katherine Gorge'], gastronomie: ['Crocodile grillé', 'Barramundi de Darwin', 'Witjuti grubs (larves d\'acacia, cuisine Aborigène)', 'Mango du NT'], histoire: "Darwin, bombardée 64 fois par le Japon (1942, 188 morts). Cyclone Tracy détruit Darwin (1974). Uluru, territoire rendu aux Anangu (1985). Intervention du NT (2007, mesures controversées contre violence dans communautés Aborigènes).", personnages: ['Les Anangu (gardiens d\'Uluru)', 'Tracker Tilmouth (leader Aborigène)'] },
